// ============================================================================
// quote_grounding (Batch Deterministic Tool: anti-hallucination guardrail)
// SLIM RETURN VARIANT (P3a): drops results[] when all_grounded=true and
// drops matched_text from per-result objects. Verbose debug retained on
// $execution.customData for n8n execution-log visibility (Loom narration).
// ============================================================================

const input = $input.first().json;
const utterances = input.utterances;
const evidenceList = input.evidence_list;

function isString(v) { return typeof v === 'string'; }
function isArray(v)  { return Array.isArray(v); }
function normalize(s) { return s.toLowerCase().trim().replace(/\s+/g, ' '); }

function stashDebug(debug) {
  try {
    if ($execution && typeof $execution.customData?.set === 'function') {
      $execution.customData.set('quote_grounding_debug', JSON.stringify(debug).slice(0, 8000));
    }
  } catch (e) { /* customData unavailable in test mode -- silent */ }
}

// --- Input validation ---------------------------------------------------
if (!isArray(utterances) || utterances.length === 0) {
  return [{ json: {
    all_grounded: false,
    failed_fields: [],
    summary: 'invalid_input: utterances missing or empty',
    total_claims: 0,
    grounded_count: 0,
    error: true
  }}];
}
if (!isArray(evidenceList)) {
  return [{ json: {
    all_grounded: false,
    failed_fields: [],
    summary: 'invalid_input: evidence_list must be an array',
    total_claims: 0,
    grounded_count: 0,
    error: true
  }}];
}
if (evidenceList.length === 0) {
  return [{ json: {
    all_grounded: true,
    failed_fields: [],
    summary: 'no_claims: evidence_list empty (abstain mode or no fields populated)',
    total_claims: 0,
    grounded_count: 0,
    error: false
  }}];
}

// --- Build O(1) timestamp lookup ----------------------------------------
const utteranceByTimestamp = {};
for (let i = 0; i < utterances.length; i++) {
  const u = utterances[i];
  if (u && isString(u.timestamp_raw)) {
    utteranceByTimestamp[u.timestamp_raw] = { utterance: u, index: i };
  }
}

// --- Iterate all evidence ----------------------------------------------
const fullResults = [];
const failedResults = [];
const failedFields = [];
let groundedCount = 0;

for (let i = 0; i < evidenceList.length; i++) {
  const ev = evidenceList[i] || {};
  const field = ev.field;
  const value = ev.value === undefined ? null : ev.value;
  const quote = ev.quote;
  const timestamp = ev.timestamp;

  let result;

  if (!isString(field) || field.length === 0) {
    result = { field: field || '<missing>', grounded: false, reason: 'invalid_input: field missing or empty' };
    failedFields.push(field || '<missing>');
  } else if (!isString(quote) || quote.length === 0) {
    result = { field: field, grounded: false, reason: 'invalid_input: quote missing or empty' };
    failedFields.push(field);
  } else if (!isString(timestamp) || timestamp.length === 0) {
    result = { field: field, grounded: false, reason: 'invalid_input: timestamp missing or empty' };
    failedFields.push(field);
  } else {
    const lookup = utteranceByTimestamp[timestamp];
    if (!lookup) {
      result = { field: field, value: value, quote: quote, timestamp: timestamp, grounded: false, reason: 'timestamp_not_found: ' + timestamp + ' does not exist in this transcript' };
      failedFields.push(field);
    } else {
      const utteranceText = lookup.utterance.text;
      if (!isString(utteranceText) || utteranceText.length === 0) {
        result = { field: field, value: value, quote: quote, timestamp: timestamp, grounded: false, reason: 'utterance_text_missing' };
        failedFields.push(field);
      } else {
        const grounded = normalize(utteranceText).indexOf(normalize(quote)) !== -1;
        if (!grounded) {
          result = { field: field, value: value, quote: quote, timestamp: timestamp, grounded: false, reason: 'quote_not_in_utterance: quote does not appear in the utterance at ' + timestamp };
          failedFields.push(field);
        } else {
          result = { field: field, grounded: true, reason: null };
          groundedCount++;
        }
      }
    }
  }

  fullResults.push(result);
  if (!result.grounded) failedResults.push(result);
}

const allGrounded = groundedCount === evidenceList.length;

stashDebug({ all_grounded: allGrounded, results: fullResults, summary: groundedCount + '/' + evidenceList.length + ' grounded' });

if (allGrounded) {
  return [{ json: {
    all_grounded: true,
    failed_fields: [],
    summary: groundedCount + '/' + evidenceList.length + ' grounded',
    total_claims: evidenceList.length,
    grounded_count: groundedCount,
    error: false
  }}];
}

return [{ json: {
  all_grounded: false,
  results: failedResults,
  failed_fields: failedFields,
  summary: groundedCount + '/' + evidenceList.length + ' grounded',
  total_claims: evidenceList.length,
  grounded_count: groundedCount,
  error: false
}}];
